public static int shortest_path_length(Map<List<Node>, Integer> length_by_edge, Node startnode, Node goalnode) {
    Map<Node, Integer> distances = new HashMap<>();
    Map<Node, Node> previousNodes = new HashMap<>();
    PriorityQueue<Node> priorityQueue = new PriorityQueue<>(Comparator.comparingInt(distances::get));
    Set<Node> visitedNodes = new HashSet<>();

    distances.put(startnode, 0);
    priorityQueue.add(startnode);

    while (!priorityQueue.isEmpty()) {
        Node currentNode = priorityQueue.poll();

        if (currentNode.equals(goalnode)) {
            return distances.get(currentNode);
        }

        if (!visitedNodes.add(currentNode)) {
            continue;
        }

        for (Node neighbor : currentNode.getSuccessors()) {
            if (visitedNodes.contains(neighbor)) {
                continue;
            }

            int newDistance = distances.getOrDefault(currentNode, Integer.MAX_VALUE) +
                    length_by_edge.getOrDefault(Arrays.asList(currentNode, neighbor), Integer.MAX_VALUE);

            if (newDistance < distances.getOrDefault(neighbor, Integer.MAX_VALUE)) {
                distances.put(neighbor, newDistance);
                previousNodes.put(neighbor, currentNode);
                priorityQueue.add(neighbor);
            }
        }
    }

    return Integer.MAX_VALUE;
}

