public static Map<List<Integer>, Integer> shortest_path_lengths(int numNodes, Map<List<Integer>, Integer> length_by_edge) {
    Map<List<Integer>, Integer> length_by_path = new HashMap<>();
    int INF = Integer.MAX_VALUE;

    for (int i = 0; i < numNodes; i++) {
        for (int j = 0; j < numNodes; j++) {
            List<Integer> edge = Arrays.asList(i, j);
            if (i == j) {
                length_by_path.put(edge, 0);
            } else if (length_by_edge.containsKey(edge)) {
                length_by_path.put(edge, length_by_edge.get(edge));
            } else {
                length_by_path.put(edge, INF);
            }
        }
    }

    for (int k = 0; k < numNodes; k++) {
        for (int i = 0; i < numNodes; i++) {
            for (int j = 0; j < numNodes; j++) {
                List<Integer> ik = Arrays.asList(i, k);
                List<Integer> kj = Arrays.asList(k, j);
                List<Integer> ij = Arrays.asList(i, j);

                if (length_by_path.get(ik) != INF && length_by_path.get(kj) != INF) {
                    int new_length = length_by_path.get(ik) + length_by_path.get(kj);
                    length_by_path.put(ij, Math.min(length_by_path.get(ij), new_length));
                }
            }
        }
    }

